import type { CotizacionWorkflowRecord } from "@/types/cotizacion-workflow";

function escapeHtml(value: string) {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function formatCurrency(value: number) {
  return new Intl.NumberFormat("es-CL", {
    style: "currency",
    currency: "CLP",
    maximumFractionDigits: 0,
  }).format(value);
}

export function openCotizacionesListPdf(
  records: CotizacionWorkflowRecord[],
  title = "Listado de cotizaciones"
) {
  if (typeof window === "undefined") {
    return;
  }

  const printWindow = window.open("", "_blank", "noopener,noreferrer");

  if (!printWindow) {
    throw new Error("No se pudo abrir la ventana de impresion");
  }

  const rows = records
    .map(
      (record) => `
        <tr>
          <td>${escapeHtml(record.codigo)}</td>
          <td>${escapeHtml(record.clienteNombre)}</td>
          <td>${escapeHtml(record.obra)}</td>
          <td>${escapeHtml(record.updatedAt.slice(0, 10))}</td>
          <td>${escapeHtml(record.estado)}</td>
          <td>${escapeHtml(formatCurrency(record.total))}</td>
        </tr>
      `
    )
    .join("");

  printWindow.document.write(`
    <html lang="es">
      <head>
        <title>${escapeHtml(title)}</title>
        <style>
          body { font-family: Arial, sans-serif; margin: 32px; color: #243b6b; }
          h1 { margin: 0 0 8px; }
          p { margin: 0 0 24px; color: #667085; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #d9e0ea; padding: 10px 12px; text-align: left; font-size: 12px; }
          th { background: #eef3f8; text-transform: uppercase; letter-spacing: 0.08em; }
        </style>
      </head>
      <body>
        <h1>${escapeHtml(title)}</h1>
        <p>Total de cotizaciones: ${records.length}</p>
        <table>
          <thead>
            <tr>
              <th>Codigo</th>
              <th>Cliente</th>
              <th>Obra</th>
              <th>Fecha</th>
              <th>Estado</th>
              <th>Total</th>
            </tr>
          </thead>
          <tbody>
            ${rows}
          </tbody>
        </table>
        <script>
          window.onload = () => {
            window.print();
          };
        </script>
      </body>
    </html>
  `);
  printWindow.document.close();
}
